import { BaseEntity } from '../../../shared/domain/entity';
import type { AppointmentStatus, RentalTenantConfirmationStatus, CancellationReasonCode, RejectionReasonCode, AppointmentCustomField } from '@properfy/shared';
import { TRANSITION_RULES } from './appointment-state-machine';

export interface AppointmentProps {
  id: string;
  /** Auto-generated by the DB on insert. Use 0 as placeholder for in-memory entities before first DB round-trip. */
  appointmentNumber?: number;
  tenantId: string;
  branchId: string;
  propertyId: string;
  serviceTypeId: string;
  inspectorId: string | null;
  status: AppointmentStatus;
  scheduledDate: Date;
  timeSlotStart: string;
  timeSlotEnd: string;
  keyRequired: boolean;
  meetingLocation: string | null;
  keyLocation: string | null;
  rentalTenantConfirmationStatus: RentalTenantConfirmationStatus;
  activeConfirmationCycleId?: string | null;
  priceAmount: number;
  payoutAmount: number;
  pricingRuleSnapshotJson: Record<string, unknown>;
  notes: string | null;
  rentalTenantNote?: string | null;
  /** Operational free-text note set on direct create/edit (distinct from rental-tenant-portal `notes`/`rentalTenantNote`). */
  observation?: string | null;
  customFieldsJson: AppointmentCustomField[] | null;
  reason: string | null;
  cancellationReasonCode: CancellationReasonCode | null;
  rejectionReasonCode: RejectionReasonCode | null;
  createdByUserId: string;
  doneMarkedByUserId: string | null;
  doneCheckedByUserId: string | null;
  doneCheckedAt: Date | null;
  serviceGroupId: string | null;
  createdAt: Date;
  updatedAt: Date;
  deletedAt: Date | null;
}

export class AppointmentEntity extends BaseEntity {
  readonly appointmentNumber: number;
  readonly tenantId: string;
  readonly branchId: string;
  readonly propertyId: string;
  readonly serviceTypeId: string;
  inspectorId: string | null;
  status: AppointmentStatus;
  readonly scheduledDate: Date;
  readonly timeSlotStart: string;
  readonly timeSlotEnd: string;
  readonly keyRequired: boolean;
  readonly meetingLocation: string | null;
  readonly keyLocation: string | null;
  rentalTenantConfirmationStatus: RentalTenantConfirmationStatus;
  readonly activeConfirmationCycleId: string | null;
  readonly priceAmount: number;
  readonly payoutAmount: number;
  readonly pricingRuleSnapshotJson: Record<string, unknown>;
  readonly notes: string | null;
  readonly rentalTenantNote: string | null;
  readonly observation: string | null;
  readonly customFieldsJson: AppointmentCustomField[] | null;
  reason: string | null;
  cancellationReasonCode: CancellationReasonCode | null;
  rejectionReasonCode: RejectionReasonCode | null;
  readonly createdByUserId: string;
  doneMarkedByUserId: string | null;
  doneCheckedByUserId: string | null;
  doneCheckedAt: Date | null;
  serviceGroupId: string | null;
  deletedAt: Date | null;

  constructor(props: AppointmentProps) {
    super(props.id, props.createdAt, props.updatedAt);
    this.appointmentNumber = props.appointmentNumber ?? 0;
    this.tenantId = props.tenantId;
    this.branchId = props.branchId;
    this.propertyId = props.propertyId;
    this.serviceTypeId = props.serviceTypeId;
    this.inspectorId = props.inspectorId;
    this.status = props.status;
    this.scheduledDate = props.scheduledDate;
    this.timeSlotStart = props.timeSlotStart;
    this.timeSlotEnd = props.timeSlotEnd;
    this.keyRequired = props.keyRequired;
    this.meetingLocation = props.meetingLocation;
    this.keyLocation = props.keyLocation;
    this.rentalTenantConfirmationStatus = props.rentalTenantConfirmationStatus;
    this.activeConfirmationCycleId = props.activeConfirmationCycleId ?? null;
    this.priceAmount = props.priceAmount;
    this.payoutAmount = props.payoutAmount;
    this.pricingRuleSnapshotJson = props.pricingRuleSnapshotJson;
    this.notes = props.notes;
    this.rentalTenantNote = props.rentalTenantNote ?? null;
    this.observation = props.observation ?? null;
    this.customFieldsJson = props.customFieldsJson;
    this.reason = props.reason;
    this.cancellationReasonCode = props.cancellationReasonCode;
    this.rejectionReasonCode = props.rejectionReasonCode;
    this.createdByUserId = props.createdByUserId;
    this.doneMarkedByUserId = props.doneMarkedByUserId;
    this.doneCheckedByUserId = props.doneCheckedByUserId;
    this.doneCheckedAt = props.doneCheckedAt;
    this.serviceGroupId = props.serviceGroupId;
    this.deletedAt = props.deletedAt;
  }

  isEditable(): boolean {
    return this.status === 'DRAFT' || this.status === 'AWAITING_INSPECTOR';
  }

  isActive(): boolean {
    return this.deletedAt === null;
  }

  isDeleted(): boolean {
    return this.deletedAt !== null;
  }

  canTransitionTo(target: AppointmentStatus): boolean {
    return TRANSITION_RULES.some((r) => r.from === this.status && r.to === target);
  }
}
